let mut parser = preceded(tag("abc"), tag("efg"));

assert_eq!(parser.parse("abcefg"), Ok(("", "efg")));
assert_eq!(parser.parse("abcefghij"), Ok(("hij", "efg")));
assert_eq!(parser.parse(""), Err(Err::Error(("", ErrorKind::Tag))));
